const raw = (process.env.ARGS || process.env.INPUT || '').trim();
const m = raw.match(/^(\d*)\s*[dD]\s*(\d+)$/);
let n = m ? parseInt(m[1] || '1', 10) : 1;
let sides = m ? parseInt(m[2], 10) : 6;
if (!Number.isFinite(n) || n < 1) n = 1;
if (n > 100) n = 100;
if (!Number.isFinite(sides) || sides < 2) sides = 6;
if (sides > 1000) sides = 1000;
const rolls = [];
let total = 0;
for (let i = 0; i < n; i++) {
  const r = Math.floor(Math.random() * sides) + 1;
  rolls.push(r);
  total += r;
}
console.log('\uD83C\uDFB2 ' + n + 'd' + sides + ': [' + rolls.join(', ') + '] = ' + total);

